def track_viral_indicators(sends, opens, forwards, new_subscribers_from_referrals): """ Tracks viral loop stages and projects growth.
Stages: 1. Sends 2. Opens (open rate) 3. Forwards (forward rate) 4. New subscribers (conversion rate) 5. Loop repeats
Returns: dict: { 'viral_stages': dict, 'viral_coefficient': float, 'growth_projection': dict } """ # Calculate rates open_rate = (opens / sends) * 100 if sends > 0 else 0 forward_rate = (forwards / opens) * 100 if opens > 0 else 0 conversion_rate = (new_subscribers_from_referrals / forwards) * 100 if forwards > 0 else 0
# Viral coefficient: K = (forwards / sends) × (new subs / forwards) K = (forwards / sends) * (new_subscribers_from_referrals / forwards) if sends > 0 and forwards > 0 else 0
viral_stages = { 'stage_1_sends': sends, 'stage_2_opens': opens, 'stage_3_forwards': forwards, 'stage_4_new_subscribers': new_subscribers_from_referrals, 'open_rate': round(open_rate, 2), 'forward_rate': round(forward_rate, 2), 'conversion_rate': round(conversion_rate, 2) }
# Growth projection (simplified exponential) # After N emails, total subscribers = initial × (1 + K)^N projections = {} initial_subs = sends for emails_sent in [10, 25, 52]: # 10 emails, 25 emails, 52 emails (1 year weekly) projected = initial_subs * ((1 + K) ** emails_sent) growth_pct = ((projected - initial_subs) / initial_subs) * 100 projections[f'after_{emails_sent}_emails'] = { 'total_subscribers': int(projected), 'growth_percentage': round(growth_pct, 1) }
return { 'viral_stages': viral_stages, 'viral_coefficient': round(K, 4), 'growth_projection': projections }

def generate_convection_report(email_history): """ Generates convection performance report.
Returns: dict: { 'overall_metrics': dict, 'top_performers': list, 'pattern_analysis': dict, 'trend': str, 'recommendations': list } """ from collections import Counter
if not email_history: return {'error': 'No email history provided'}
# Overall metrics avg_forward_rate = sum(e.get('forward_rate', 0) for e in email_history) / len(email_history) avg_heat_index = sum(e.get('heat_index', 0) for e in email_history) / len(email_history)
total_forwards = sum(e.get('forwards', 0) for e in email_history) total_new_subs_from_referrals = sum(e.get('new_subs_referral', 0) for e in email_history)
overall_metrics = { 'avg_forward_rate': round(avg_forward_rate, 2), 'avg_heat_index': round(avg_heat_index, 1), 'total_forwards': total_forwards, 'total_new_subscribers_from_convection': total_new_subs_from_referrals, 'emails_analyzed': len(email_history) }
# Top performers (top 5 by heat index) sorted_emails = sorted(email_history, key=lambda x: x.get('heat_index', 0), reverse=True) top_performers = [ { 'subject': e.get('subject', 'Unknown'), 'heat_index': e.get('heat_index', 0), 'forward_rate': e.get('forward_rate', 0) } for e in sorted_emails[:5] ]
# Pattern analysis all_patterns = [] for email in email_history: patterns = email.get('patterns_detected', []) all_patterns.extend(patterns)
pattern_counts = Counter(all_patterns)
pattern_analysis = { 'most_common_pattern': pattern_counts.most_common(1)[0] if pattern_counts else ('none', 0), 'pattern_distribution': dict(pattern_counts) }
# Trend analysis (first half vs second half) mid_point = len(email_history) // 2 first_half_avg = sum(e.get('heat_index', 0) for e in email_history[:mid_point]) / mid_point if mid_point > 0 else 0 second_half_avg = sum(e.get('heat_index', 0) for e in email_history[mid_point:]) / (len(email_history) - mid_point) if len(email_history) > mid_point else 0
if second_half_avg > first_half_avg * 1.1: trend = 'improving' elif second_half_avg < first_half_avg * 0.9: trend = 'declining' else: trend = 'stable'
# Recommendations recommendations = []
if avg_forward_rate < 0.5: recommendations.append('Low forward rate overall - apply convection patterns more consistently')
if pattern_counts: most_common = pattern_counts.most_common(1)[0][0] recommendations.append(f'Top pattern is "{most_common}" - continue using this pattern')
if trend == 'declining': recommendations.append('Convection declining - review recent emails for missing patterns') elif trend == 'improving': recommendations.append('Convection improving - keep current strategy')
return { 'overall_metrics': overall_metrics, 'top_performers': top_performers, 'pattern_analysis': pattern_analysis, 'trend': trend, 'recommendations': recommendations }
